import{_ as t,o as a,c as r,a2 as o}from"./chunks/framework.BKG_UbFK.js";const p=JSON.parse('{"title":"परिचय","description":"","frontmatter":{},"headers":[],"relativePath":"hi/guide/introduction.md","filePath":"hi/guide/introduction.md"}'),i={name:"hi/guide/introduction.md"};function d(s,e,n,l,c,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="परिचय" tabindex="-1">परिचय <a class="header-anchor" href="#परिचय" aria-label="Permalink to &quot;परिचय&quot;">​</a></h1><h2 id="clearance-क्या-है" tabindex="-1">Clearance क्या है? <a class="header-anchor" href="#clearance-क्या-है" aria-label="Permalink to &quot;Clearance क्या है?&quot;">​</a></h2><p>Clearance, <a href="https://github.com/spatie/laravel-permission" target="_blank" rel="noreferrer">spatie/laravel-permission</a> के ऊपर बना Laravel एप्लिकेशनों के लिए एक drop-in एडमिन पैनल है। यह अनुमतियों, भूमिकाओं, गार्ड और सेटिंग्स को प्रबंधित करने के लिए एक Livewire 4 + Flux UI पैनल, साथ ही एक प्रासंगिक प्राधिकरण परत और भूमिका सीलिंग जोड़ता है - एक artisan कमांड से इंस्टॉल करने योग्य, बिना किसी Spatie टेबल में बदलाव किए।</p><p>Clearance आपको देता है:</p><ul><li><strong>एडमिन पैनल</strong> अनुमतियों, भूमिकाओं, गार्ड, सेटिंग्स और एक डैशबोर्ड के लिए - पहले से बने रूट्स का उपयोग करें या प्रत्येक Livewire कंपोनेंट को अलग-अलग एम्बेड करें।</li><li><strong>प्रासंगिक प्राधिकरण</strong> - किसी विशिष्ट मॉडल इंस्टेंस (एक Store, एक Tenant, एक Project) तक सीमित भूमिका या अनुमति प्रदान करें, <code>$user-&gt;canIn()</code>, <code>@canin</code>/<code>@hasrolein</code> Blade directives, और <code>User</code> मॉडल के बाहर उपयोग के लिए एक <code>ContextService</code> के साथ।</li><li><strong>सीलिंग भूमिकाएं</strong> - एक भूमिका एक पैरेंट भूमिका घोषित कर सकती है जिसका अनुमति सेट एक ऊपरी सीमा के रूप में कार्य करता है; एक चाइल्ड भूमिका अपने पैरेंट से कभी अधिक नहीं हो सकती, यह हर सेव पर स्वचालित रूप से लागू होता है।</li><li><strong>सूक्ष्म-स्तरीय write अनुमतियाँ</strong> - प्रत्येक पैनल सेक्शन के लिए एक सौंपी जा सकने वाली <code>clearance-{section}-write</code> अनुमति, ताकि आप &quot;manage roles&quot; की अनुमति दे सकें बिना &quot;manage settings&quot; की अनुमति दिए।</li><li><strong>सुपर एडमिन</strong> एक वैकल्पिक ग्लोबल Gate bypass के साथ, मौजूदा एडमिन-जैसी भूमिकाओं के लिए alias डिटेक्शन, और सुरक्षित non-destructive प्रमोशन।</li><li><strong>Users मॉड्यूल</strong> (वैकल्पिक) - एक प्रति-उपयोगकर्ता पैनल से, भूमिकाएं वैश्विक रूप से या किसी विशिष्ट संदर्भ को असाइन करें, साथ ही प्रति-संदर्भ अनुमति ओवरराइड भी।</li><li><strong>सेटिंग्स पैनल</strong> - प्रति-भूमिका/गार्ड डिस्प्ले नाम, विवरण, sanitized SVG आइकन और रंग; auto-assign और bulk-assign के साथ एक कॉन्फ़िगर करने योग्य डिफ़ॉल्ट भूमिका।</li><li><strong>गार्ड प्रबंधन</strong> - डेटाबेस-समर्थित गार्ड, boot के समय <code>auth.guards</code> में इंजेक्ट किए गए, drivers के एक allow-listed सेट तक सीमित।</li><li><strong>9 बंडल की गई भाषाएं</strong> (ar, en, es, fr, hi, it, pt, ru, zh), key-parity टेस्ट की गई।</li><li><strong>Extensibility hooks</strong> - <code>HasClearance</code> trait, <code>HasPermissionGroups</code> trait, <code>ClearanceContextable</code> contract, फिर से उपयोग करने योग्य Blade components।</li><li><strong>SVG sanitization</strong> - हर उपयोगकर्ता-प्रदत्त आइकन स्टोरेज से पहले एक allow-list sanitizer से होकर गुजरता है।</li><li><strong>सुरक्षा-सुदृढ़</strong> - हर अनुमति-प्रदान करने वाले पथ पर privilege-escalation सीलिंग, deny-प्राथमिकता वाले संदर्भ ओवरराइड, सुरक्षित <code>clearance-*</code> नेमस्पेस। देखें <a href="/clearance-docs/hi/guide/security.html">सुरक्षा</a>।</li></ul><h2 id="spatie-laravel-permission-के-साथ-संबंध" tabindex="-1">spatie/laravel-permission के साथ संबंध <a class="header-anchor" href="#spatie-laravel-permission-के-साथ-संबंध" aria-label="Permalink to &quot;spatie/laravel-permission के साथ संबंध&quot;">​</a></h2><p>Clearance, Spatie के permission पैकेज का प्रतिस्थापन नहीं है - यह इसके ऊपर एक UI और प्राधिकरण परत है। भूमिकाएं और अनुमतियाँ अभी भी Spatie के <code>Role</code> और <code>Permission</code> मॉडल हैं, अभी भी Spatie की <code>roles</code>, <code>permissions</code>, <code>model_has_roles</code>, <code>model_has_permissions</code> और <code>role_has_permissions</code> टेबल्स में संग्रहीत हैं। Clearance उन टेबल्स को कभी नहीं बदलता। Clearance जो कुछ भी जोड़ता है - डिस्प्ले मेटाडेटा, भूमिका दायरा, सीलिंग, प्रासंगिक असाइनमेंट, प्रति-संदर्भ ओवरराइड - वह अपने खुद के <code>clr_*</code> टेबल्स के सेट में रहता है। पूरी जानकारी के लिए देखें <a href="/clearance-docs/hi/guide/architecture.html">आर्किटेक्चर</a>।</p><h2 id="आवश्यकताएं" tabindex="-1">आवश्यकताएं <a class="header-anchor" href="#आवश्यकताएं" aria-label="Permalink to &quot;आवश्यकताएं&quot;">​</a></h2><table tabindex="0"><thead><tr><th>निर्भरता</th><th>संस्करण</th></tr></thead><tbody><tr><td>PHP</td><td>^8.3</td></tr><tr><td>Laravel</td><td>^11.0 | ^12.0 | ^13.0</td></tr><tr><td>spatie/laravel-permission</td><td>^6.0</td></tr><tr><td>livewire/livewire</td><td>^3.0 | ^4.0</td></tr><tr><td>livewire/flux</td><td>^2.14</td></tr></tbody></table><h2 id="मुख्य-अवधारणाएं" tabindex="-1">मुख्य अवधारणाएं <a class="header-anchor" href="#मुख्य-अवधारणाएं" aria-label="Permalink to &quot;मुख्य अवधारणाएं&quot;">​</a></h2><table tabindex="0"><thead><tr><th>अवधारणा</th><th>सारांश</th></tr></thead><tbody><tr><td>Permission</td><td><code>group-action</code> नामकरण परंपरा का पालन करने वाली एक Spatie अनुमति (जैसे <code>orders-create</code>)। एक क्षमता प्रदान करती है।</td></tr><tr><td>भूमिका दायरा</td><td>हर भूमिका या तो <code>global</code> है (सीधे असाइन की गई, हर जगह लागू होती है) या <code>contextual</code> (विशिष्ट मॉडल प्रकारों से जुड़ी, केवल किसी संदर्भ इंस्टेंस के भीतर असाइन करने योग्य)।</td></tr><tr><td>सीलिंग भूमिका</td><td>एक भूमिका एक पैरेंट भूमिका घोषित कर सकती है जिसका अनुमति सेट एक ऊपरी सीमा है - चाइल्ड कभी भी इससे अधिक नहीं हो सकती।</td></tr><tr><td>संदर्भ (Context)</td><td>एक मॉडल इंस्टेंस (एक Store, एक Tenant, एक Project) जिस तक कोई भूमिका या अनुमति ओवरराइड सीमित हो सकता है।</td></tr><tr><td>ओवरराइड</td><td>एक प्रति-उपयोगकर्ता, प्रति-संदर्भ <code>forced_on</code>/<code>forced_off</code> अनुमति अनुदान या अस्वीकृति - एक deny हमेशा जीतती है।</td></tr></tbody></table><p>इनमें से प्रत्येक के लिए एक पूरा पेज है: <a href="/clearance-docs/hi/features/permissions.html">अनुमतियाँ</a>, <a href="/clearance-docs/hi/features/roles.html">भूमिकाएं</a>, <a href="/clearance-docs/hi/features/contextual-authorization.html">प्रासंगिक प्राधिकरण</a>, <a href="/clearance-docs/hi/features/users.html">उपयोगकर्ता</a>, <a href="/clearance-docs/hi/features/super-admin.html">सुपर एडमिन</a>।</p><h2 id="अगले-कदम" tabindex="-1">अगले कदम <a class="header-anchor" href="#अगले-कदम" aria-label="Permalink to &quot;अगले कदम&quot;">​</a></h2><p>Clearance इंस्टॉल करने के लिए तैयार हैं? <a href="/clearance-docs/hi/guide/installation.html">इंस्टॉलेशन गाइड</a> पर जारी रखें।</p>',14)])])}const m=t(i,[["render",d]]);export{p as __pageData,m as default};
